// Helper to initialize data if empty
const initializeData = () => {
    if (typeof window === 'undefined') return;

    const initKey = (key: string, data: any) => {
        if (!localStorage.getItem(key)) localStorage.setItem(key, JSON.stringify(data));
    };

    initKey(KEYS.EVENTS, eventsData);
    initKey(KEYS.BLOGS, postsData);
    initKey(KEYS.COURSES, coursesData);
    initKey(KEYS.PAGES, defaultPages);

    // Smartly merge settings to add new fields without overwriting user changes
    const existingSettings = JSON.parse(localStorage.getItem(KEYS.SETTINGS) || '{}');
    const mergedSettings = {
        ...defaultSettings,
        ...existingSettings,
        general: { ...defaultSettings.general, ...existingSettings.general },
        homepage: {
            ...defaultSettings.homepage,
            ...(existingSettings.homepage || {}),
            slider: { ...defaultSettings.homepage.slider, ...(existingSettings.homepage?.slider || {}) },
            pillars: existingSettings.homepage?.pillars && existingSettings.homepage.pillars.length > 0 ? existingSettings.homepage.pillars : defaultSettings.homepage.pillars,
            testimonials: existingSettings.homepage?.testimonials && existingSettings.homepage.testimonials.length > 0 ? existingSettings.homepage.testimonials : defaultSettings.homepage.testimonials,
            sections: { ...defaultSettings.homepage.sections, ...(existingSettings.homepage?.sections || {}) },
        },
        navigation: { ...defaultSettings.navigation, ...existingSettings.navigation },
        scripts: { ...defaultSettings.scripts, ...existingSettings.scripts },
        features: { ...defaultSettings.features, ...existingSettings.features },
    };
    localStorage.setItem(KEYS.SETTINGS, JSON.stringify(mergedSettings));
};

if (typeof window !== 'undefined') {
    initializeData();
}

export const ContentManager = {
    // --- SETTINGS ---
    getSettings: (): GlobalSettings => {
        if (typeof window === 'undefined') return defaultSettings;
        const data = localStorage.getItem(KEYS.SETTINGS);
        return data ? JSON.parse(data) : defaultSettings;
    },
    saveSettings: (settings: GlobalSettings) => {
        if (typeof window === 'undefined') return;
        localStorage.setItem(KEYS.SETTINGS, JSON.stringify(settings));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },

    // --- PAGES ---
    getPages: (): PageMetadata[] => {
        if (typeof window === 'undefined') return defaultPages;
        const data = localStorage.getItem(KEYS.PAGES);
        return data ? JSON.parse(data) : defaultPages;
    },
    savePage: (page: PageMetadata) => {
        if (typeof window === 'undefined') return;
        const pages = ContentManager.getPages();
        const index = pages.findIndex(p => p.id === page.id);
        page.lastModified = new Date().toISOString();
        if (index >= 0) pages[index] = page;
        else pages.push(page);
        localStorage.setItem(KEYS.PAGES, JSON.stringify(pages));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },

    // --- EVENTS ---
    getEvents: (): Event[] => {
        if (typeof window === 'undefined') return eventsData;
        const data = localStorage.getItem(KEYS.EVENTS);
        return data ? JSON.parse(data) : [];
    },
    saveEvent: (event: Event) => {
        if (typeof window === 'undefined') return;
        const events = ContentManager.getEvents();
        const index = events.findIndex(e => e.id === event.id);
        if (index >= 0) events[index] = event;
        else events.unshift(event);
        localStorage.setItem(KEYS.EVENTS, JSON.stringify(events));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },
    deleteEvent: (id: string) => {
        if (typeof window === 'undefined') return;
        const events = ContentManager.getEvents().filter(e => e.id !== id);
        localStorage.setItem(KEYS.EVENTS, JSON.stringify(events));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },

    // --- BLOGS ---
    getPosts: (): Post[] => {
        if (typeof window === 'undefined') return postsData;
        const data = localStorage.getItem(KEYS.BLOGS);
        return data ? JSON.parse(data) : [];
    },
    savePost: (post: Post) => {
        if (typeof window === 'undefined') return;
        const posts = ContentManager.getPosts();
        const index = posts.findIndex(p => p.id === post.id);
        post.publishDate = new Date().toISOString(); // Update date on save
        if (index >= 0) posts[index] = post;
        else posts.unshift(post);
        localStorage.setItem(KEYS.BLOGS, JSON.stringify(posts));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },
    deletePost: (id: number) => {
        if (typeof window === 'undefined') return;
        const posts = ContentManager.getPosts().filter(p => p.id !== id);
        localStorage.setItem(KEYS.BLOGS, JSON.stringify(posts));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },

    // --- COURSES ---
    getCourses: (): Course[] => {
        if (typeof window === 'undefined') return coursesData;
        const data = localStorage.getItem(KEYS.COURSES);
        return data ? JSON.parse(data) : [];
    },
    saveCourse: (course: Course) => {
        if (typeof window === 'undefined') return;
        const courses = ContentManager.getCourses();
        const index = courses.findIndex(c => c.id === course.id);
        if (index >= 0) courses[index] = course;
        else courses.unshift(course);
        localStorage.setItem(KEYS.COURSES, JSON.stringify(courses));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },
    deleteCourse: (id: number) => {
        if (typeof window === 'undefined') return;
        const courses = ContentManager.getCourses().filter(c => c.id !== id);
        localStorage.setItem(KEYS.COURSES, JSON.stringify(courses));
        window.dispatchEvent(new Event('masa-settings-updated'));
    },
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Testimonial, NavigationProps } from '../types';
import { QuoteIcon, ArrowRightIcon } from './icons/FeatureIcons';
import { ChevronLeftIcon, ChevronRightIcon } from './icons/UiIcons';
import { ContentManager } from '../utils/contentManager';

const CommunityVoicesSection: React.FC<NavigationProps> = ({ navigateTo }) => {
    const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const timeoutRef = useRef<number | null>(null);
    const [sectionSettings, setSectionSettings] = useState(ContentManager.getSettings().homepage.sections.communityVoices);

    useEffect(() => {
        const loadContent = () => {
            const settings = ContentManager.getSettings();
            setTestimonials((settings.homepage.testimonials || []).slice(0, 6));
            setSectionSettings(settings.homepage.sections.communityVoices);
        };
        loadContent();
        window.addEventListener('masa-settings-updated', loadContent);
        return () => window.removeEventListener('masa-settings-updated', loadContent);
    }, []);

    const resetTimeout = useCallback(() => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }
    }, []);

    const nextSlide = useCallback(() => {
        setCurrentIndex(prevIndex =>
            prevIndex === testimonials.length - 1 ? 0 : prevIndex + 1
        );
    }, [testimonials.length]);

    useEffect(() => {
        resetTimeout();
        if (testimonials.length > 1) {
            timeoutRef.current = window.setTimeout(nextSlide, 7000);
        }
        return () => {
            resetTimeout();
        };
    }, [currentIndex, testimonials.length, resetTimeout, nextSlide]);

    const prevSlide = () => {
        setCurrentIndex(prevIndex =>
            prevIndex === 0 ? testimonials.length - 1 : prevIndex - 1
        );
    };

    const goToSlide = (slideIndex: number) => {
        setCurrentIndex(slideIndex);
    };

    if (!sectionSettings.visible || !testimonials.length) {
        return null;
    }

    return (
        <section className="py-24 bg-gray-50">
            <div 
                className="container mx-auto px-4 sm:px-6 lg:px-8"
                onMouseEnter={() => resetTimeout()}
                onMouseLeave={() => {
                    if (testimonials.length > 1) {
                        resetTimeout();
                        timeoutRef.current = window.setTimeout(nextSlide, 7000);
                    }
                }}
            >
                <div className="text-center mb-16 max-w-3xl mx-auto">
                    <h2 className="text-3xl font-bold text-masa-charcoal">{sectionSettings.title}</h2>
                    <p className="mt-4 text-lg text-gray-600">
                        {sectionSettings.subtitle}
                    </p>
                </div>

                <div 
                    className="relative max-w-3xl mx-auto"
                    role="region"
                    aria-roledescription="carousel"
                    aria-label="Community Voices"
                >
                    <div
                        id="testimonial-carousel-content"
                        className="overflow-hidden relative h-96"
                        aria-live="polite"
                    >
                        {testimonials.map((t, index) => (
                            <div
                                key={index}
                                role="group"
                                aria-roledescription="slide"
                                aria-label={`Testimonial ${index + 1} of ${testimonials.length}`}
                                aria-hidden={index !== currentIndex}
                                className={`absolute inset-0 transition-opacity duration-700 ease-in-out ${index === currentIndex ? 'opacity-100' : 'opacity-0'}`}
                            >
                                <div className="bg-white rounded-2xl shadow-xl p-8 md:p-12 h-full flex flex-col justify-center items-center text-center relative overflow-hidden border border-gray-100">
                                    <QuoteIcon className="absolute -top-4 -left-4 h-28 w-28 text-masa-blue/5" aria-hidden="true" />
                                    <blockquote className="text-xl md:text-2xl font-serif italic text-gray-700 mb-6 flex-grow flex items-center leading-relaxed">
                                        "{t.quote}"
                                    </blockquote>
                                    <div className="flex items-center gap-4 pt-6 border-t border-gray-100">
                                        <img src={t.image} alt="" className="w-14 h-14 rounded-full object-cover border-2 border-white shadow-md" />
                                        <div>
                                            <p className="font-bold text-masa-charcoal">{t.author}</p>
                                            <p className="text-sm text-gray-500 font-medium">{t.role}</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    {testimonials.length > 1 && (
                        <>
                            <button 
                                onClick={prevSlide} 
                                className="absolute top-1/2 -translate-y-1/2 -left-4 md:-left-16 bg-white p-3 rounded-full shadow-md hover:bg-gray-100 transition-colors border border-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-masa-orange"
                                aria-label="Previous testimonial"
                                aria-controls="testimonial-carousel-content"
                            >
                                <ChevronLeftIcon className="h-6 w-6 text-masa-blue" />
                            </button>
                            <button 
                                onClick={nextSlide} 
                                className="absolute top-1/2 -translate-y-1/2 -right-4 md:-right-16 bg-white p-3 rounded-full shadow-md hover:bg-gray-100 transition-colors border border-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-masa-orange"
                                aria-label="Next testimonial"
                                aria-controls="testimonial-carousel-content"
                            >
                                <ChevronRightIcon className="h-6 w-6 text-masa-blue" />
                            </button>
                        </>
                    )}
                </div>

                {testimonials.length > 1 && (
                    <div className="flex justify-center gap-2 mt-8" role="group" aria-label="Testimonial navigation">
                        {testimonials.map((_, index) => (
                            <button
                                key={index}
                                onClick={() => goToSlide(index)}
                                className={`h-3 w-3 rounded-full transition-all duration-300 ${index === currentIndex ? 'bg-masa-orange w-6' : 'bg-gray-300 hover:bg-gray-400'}`}
                                aria-label={`Go to testimonial ${index + 1}`}
                                aria-controls="testimonial-carousel-content"
                                aria-current={index === currentIndex ? 'true' : 'false'}
                            />
                        ))}
                    </div>
                )}

                <div className="text-center mt-12">
                    <button 
                        onClick={() => navigateTo('community-voices')} 
                        className="text-masa-blue font-bold hover:underline flex items-center gap-1 mx-auto group"
                    >
                        Read More Stories
                        <ArrowRightIcon className="h-4 w-4 transform group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            </div>
        </section>
    );
};

