    const handleEnrollClick = (course: Course) => {
        setSelectedCourse(null); // Close details modal if open
        setEnrollmentCourse(course); // Open enrollment modal
    };

    return (
        <div className="bg-gray-50 min-h-screen">
            {/* View Details Modal */}
